from scapy.all import rdpcap, TCP, IP, Raw
import base64
from Crypto.Cipher import AES
from Crypto.Protocol.KDF import PBKDF2
from Crypto.Hash import SHA1

KEY_PW=b"VYAemVeO3zUDTL6N62kVA"
SALT=bytes([86,101,114,121,95,83,51,99,114,51,116,95,83])
dk=PBKDF2(KEY_PW, SALT, dkLen=48, count=1000, hmac_hash_module=SHA1)
KEY=dk[:32]; IV=dk[32:48]

def dec(b64):
    try:
        ct=base64.b64decode(b64)
        c=AES.new(KEY,AES.MODE_CBC,IV)
        pt=c.decrypt(ct)
        pad=pt[-1]
        if 1<=pad<=16:
            pt=pt[:-pad]
        return pt.decode('windows-1252',errors='replace')
    except Exception as e:
        return None

